import sys
from itertools import combinations

input_data = sys.stdin.read().split()
idx = 0

def solve_length(n_str, digits):
    """Try to find smallest number of same length as n_str using only chars in digits, >= n_str"""
    digits = sorted(digits)
    L = len(n_str)

    # Build digit by digit, trying to match or exceed n_str
    # We'll use a recursive/iterative approach with backtracking
    result = [''] * L

    def helper(pos, tight, started):
        if pos == L:
            return ''.join(result)

        lo = n_str[pos] if tight else '0'

        for d in digits:
            if pos == 0 and d == '0':
                continue  # no leading zeros
            if d < lo:
                continue
            result[pos] = d
            new_tight = tight and (d == lo)
            # Fill remaining positions with smallest digit
            if not new_tight:
                # Fill rest with smallest digit
                for i in range(pos + 1, L):
                    result[i] = digits[0]
                return ''.join(result)
            else:
                res = helper(pos + 1, new_tight, True)
                if res is not None:
                    return res
        return None

    return helper(0, True, False)

def smallest_geq(n_str, digits):
    digits = sorted(digits)
    L = len(n_str)
    # Try to find number of same length
    result = solve_length(n_str, digits)
    if result is not None:
        return result
    # Try length L+1
    # smallest number of length L+1 with these digits (no leading zero)
    non_zero = [d for d in digits if d != '0']
    if not non_zero:
        return None
    return non_zero[0] + digits[0] * L

def solve(n, k):
    n_str = str(n)
    all_digits = [str(d) for d in range(10)]

    best = None

    # Try all subsets of digits of size 1 to k
    for size in range(1, k + 1):
        for subset in combinations(all_digits, size):
            subset = list(subset)
            # Check if subset has at least one non-zero digit
            if all(d == '0' for d in subset):
                continue
            res = smallest_geq(n_str, subset)
            if res is not None:
                res_int = int(res)
                if best is None or res_int < best:
                    best = res_int

    return best

t = int(input_data[idx]); idx += 1
out = []
for _ in range(t):
    n = int(input_data[idx]); idx += 1
    k = int(input_data[idx]); idx += 1
    out.append(str(solve(n, k)))

print('\n'.join(out))
